if ('parsedOptions' in style) {
  const opts = (style as NumberSkeleton).parsedOptions;
  return Object.keys(opts).length > 0
    ? (opts as NumberStyleOptions)
    : undefined;
}

if ('parsedOptions' in style) {
  const opts = (style as DateTimeSkeleton).parsedOptions;
  return Object.keys(opts).length > 0
    ? (opts as DateTimeStyleOptions)
    : undefined;
}

if (exactKey in options) {
  return formatBranch(options[exactKey], locale, values, formatOptions, {
    value,
    locale
  });
}

const category = formatOptions.formatters
    .getPluralRules(locale, {type: pluralType})
    .select(value);

throw new Error(
  "Couldn't find next-intl config file. Please follow the instructions at https://next-intl.dev/docs/getting-started/app-router"
);

if (this.isDevelopment) {
  const catalogLocales = this.getCatalogLocales();
  catalogLocales.subscribeLocalesChange(this.onLocalesChange);
}

const aggregate: ExtractorMessage = {
  description: this.mergeDescriptions(sourceMessages),
  id,
  message: sourceMessages[0].message,
  references: sourceMessages
    .map((message) => message.reference)
    .sort(compareReferences)
};

const sortedByReference = messages.toSorted((a, b) =>
      compareReferences(a.reference, b.reference)
    );

for (const message of sortedByReference) {
  const {description} = message;
  if (description != null && !merged.includes(description)) {
    merged.push(description);
  }
}

const localeMessages = isSourceLocale
      ? this.messagesById
      : this.translationsByTargetLocale.get(locale);

for (const locale of params.removed) {
  this.translationsByTargetLocale.delete(locale);
  this.lastWriteByLocale.delete(locale);
}

try {
  const outputDir = fsPath.dirname(filePath);
  await fs.mkdir(outputDir, {recursive: true});
  await fs.writeFile(filePath, content);
} catch (error) {
  console.error(`❌ Failed to write catalog: ${error}`);
}

try {
  const stats = await fs.stat(filePath);
  return stats.mtime;
} catch {
  return undefined;
}

for (const message of getSortedMessages(messages)) {
  setNestedProperty(root, message.id, message.message);
}

if (!sourceLocale) {
  throwError('`messages.sourceLocale` is required when extracting messages.');
}

if (extractPath == null) {
  if (pathIsArray) {
    throwError(
      'When `messages.path` is an array, `extract.path` is required to select the writable catalog directory.'
    );
  }
  extractPath = messagesPath[0]!;
}

return deduplicated.filter((event) => {
  // Keep all delete events (might be deleted directories that no longer exist)
  if (event.type === 'delete') {
    return true;
  }
  // Keep source files
  return SourceFileFilter.isSourceFile(event.path);
});

const shouldAddXDefault =
    // For domain-based routing there is no reasonable x-default
    !routing.domains || routing.domains.length === 0;

if (pathname) {
  locale = getPathnameMatch(
    pathname,
    routing.locales,
    routing.localePrefix
  )?.locale;
}

if (!locale && routing.localeDetection) {
  locale = getLocaleFromCookie(routing, requestCookies);
}

if (!locale && routing.localeDetection) {
  locale = getAcceptLanguageLocale(
    requestHeaders,
    routing.locales,
    routing.defaultLocale
  );
}

const prefixes = locales.map((locale) => [
  locale as AppLocales[number],
  getLocalePrefix(locale, localePrefix)
]);

for (const internalPathname of Object.keys(pathnames)) {
  if (matchesPathname(internalPathname, pathname)) {
    return [undefined, internalPathname];
  }
}

if (extract) {
  extractorConfig = normalizeExtractorConfig({
    extract,
    messages: experimental.messages,
    srcPath: experimental.srcPath
  });
}

if (async) {
  return fs.promises
    .readFile(messagesPath, 'utf-8')
    .then((content) =>
      fs.promises.writeFile(declarationPath, createDeclaration(content))
    );
}

extractor
    .extract(this.resourcePath, source)
    .then((result) => {
      callback(null, result.code, result.map);
    })
    .catch(callback);

export const useTranslations = callHook(
  'useTranslations',
  base_useTranslations
) as typeof base_useTranslations;

export const useFormatter = callHook(
  'useFormatter',
  base_useFormatter
) as typeof base_useFormatter;

if (!config.messages) {
  throw new Error(
    'No messages found. Have you configured them correctly? See https://next-intl.dev/docs/configuration#messages'
  );
}

translateFn.has = function translateHasFn(
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  ...[message]: Parameters<Return['has']>
): boolean {
  // Not really something better we can do here
  return true;
};
